-- Name: ticket_status_history; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.ticket_status_history (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    ticket_id uuid,
    old_status character varying(50),
    new_status character varying(50),
    changed_by uuid,
    created_at timestamp without time zone DEFAULT now()
);


--
-- Name: ticket_types; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.ticket_types (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(255) NOT NULL,
    category character varying(100),
    description text,
    default_queue_id uuid,
    form_schema jsonb,
    active boolean DEFAULT true,
    created_at timestamp without time zone DEFAULT now()
);


--
-- Name: tickets; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.tickets (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    ticket_number integer NOT NULL,
    subject character varying(255) NOT NULL,
    description text,
    status character varying(50) DEFAULT 'novo'::character varying,
    priority character varying(10) DEFAULT 'P3'::character varying,
    contact_id uuid,
    contract_id uuid,
    queue_id uuid,
    agent_id uuid,
    ticket_type_id uuid,
    sla_policy_id uuid,
    channel character varying(50) DEFAULT 'web'::character varying,
    sla_due_date timestamp without time zone,
    first_response_at timestamp without time zone,
    resolved_at timestamp without time zone,
    closed_at timestamp without time zone,
    tags text[],
    custom_fields jsonb,
    created_by_agent_id uuid,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now(),
    assigned_agent_id uuid,
    assigned_at timestamp without time zone,
    sla_breached boolean DEFAULT false,
    team_id uuid
);


--
-- Name: tickets_ticket_number_seq; Type: SEQUENCE; Schema: public; Owner: -
--

CREATE SEQUENCE public.tickets_ticket_number_seq
    AS integer
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


--
-- Name: tickets_ticket_number_seq; Type: SEQUENCE OWNED BY; Schema: public; Owner: -
--

ALTER SEQUENCE public.tickets_ticket_number_seq OWNED BY public.tickets.ticket_number;


--
-- Name: users; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.users (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    email character varying(255) NOT NULL,
    password_hash character varying(255) NOT NULL,
    full_name character varying(255),
    role character varying(50) DEFAULT 'user'::character varying,
    avatar_url text,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);


--
-- Name: visits; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.visits (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    lead_id uuid,
    agent_id uuid,
    scheduled_at timestamp without time zone,
    visited_at timestamp without time zone,
    check_in_lat numeric(10,8),
    check_in_lng numeric(11,8),
    notes text,
    status character varying(50) DEFAULT 'scheduled'::character varying,
    created_at timestamp without time zone DEFAULT now(),
    check_out_at timestamp without time zone,
    check_out_lat numeric(10,8),
    check_out_lng numeric(11,8),
    duration_minutes integer
);


--
-- Name: tickets ticket_number; Type: DEFAULT; Schema: public; Owner: -
--

ALTER TABLE ONLY public.tickets ALTER COLUMN ticket_number SET DEFAULT nextval('public.tickets_ticket_number_seq'::regclass);


