INSERT INTO public.kb_articles VALUES ('76a6c36c-210b-4528-a753-e8d705356404', 'Como criar sua primeira conta', 'como-criar-primeira-conta', 'Neste guia, vamos mostrar como criar sua primeira conta no sistema. Acesse o site e clique em Criar Conta...', NULL, NULL, 'published', 150, 45, 3, '{inicio,conta}', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117');
INSERT INTO public.kb_articles VALUES ('9112f908-ae41-4b38-a323-5a4bd25dc797', 'Configurando seu perfil', 'configurando-perfil', 'Após criar sua conta, é importante configurar seu perfil corretamente. Acesse Configurações > Perfil...', NULL, NULL, 'published', 89, 28, 1, '{perfil,configuracao}', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117');
INSERT INTO public.kb_articles VALUES ('743f2963-5a3c-43ea-9a07-b1331e7e6a80', 'Como gerar relatórios', 'como-gerar-relatorios', 'O sistema oferece diversos tipos de relatórios. Para acessar, vá em Relatórios no menu principal...', NULL, NULL, 'published', 234, 67, 5, '{relatorios,dados}', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117');
INSERT INTO public.kb_articles VALUES ('cc16b670-9da5-4592-ab15-f216af4fb32b', 'Integrando com seu ERP', 'integrando-erp', 'Para integrar com seu ERP, você precisará da chave de API. Acesse Configurações > Integrações...', NULL, NULL, 'draft', 0, 0, 0, '{integracao,erp,api}', NULL, '2025-12-18 01:59:10.684117', '2025-12-18 01:59:10.684117');
